sql:
SELECT COUNT(device_id) AS count_high_severity_updates
FROM device_updates
WHERE update_severity = 'high';

external_knowledge:
- A "couple of nanoseconds" refers to a refresh cycle time greater than 2.5 nanoseconds;
- "Decent amount of banks" signifies a bank count of 4 or more;
- The size of the rows is measured in bits.

sql:
SELECT COUNT(*) 
FROM users 
WHERE role != 'admin';

SELECT devices.device_id, device_categories.device_category
FROM devices
JOIN device_categories ON devices.device_category_id = device_categories.device_category_id;

SELECT *
FROM device_updates
WHERE device_id = 1;

SELECT update_category, update_severity, COUNT(*) AS number_of_alerts
FROM device_updates
GROUP BY update_category, update_severity;

SELECT density
FROM devices
WHERE row_count > (SELECT AVG(row_count) FROM devices);
